import React from "react";
import "./Settings.css";

export default function Settings() {
  return (
    <div className="settings-wrapper">
      <h2>Settings</h2>

      <div className="settings-box">
        <p>Update Profile</p>
        <p>Change Password</p>
        <p>Theme Options</p>
      </div>

      <button 
        className="settings-logout" 
        onClick={() => {
          localStorage.clear();
          window.location.href = "/";
        }}
      >
        Logout
      </button>
    </div>
  );
}
